    [Parameter, EditorRequired]
    public IReadOnlyList<TItem> Items { get; set; } = [];

    [Parameter, EditorRequired]
    public bool HasMore { get; set; }

    [Parameter, EditorRequired]
    public EventCallback OnLoadMore { get; set; }

    [Parameter, EditorRequired]
    public RenderFragment<TItem> ChildContent { get; set; } = default!;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender && HasMore)
        {
            _interop = new InfiniteScrollListInterop(JS);
            _dotNetRef = DotNetObjectReference.Create(this);
            await _interop.InitializeAsync(_sentinelRef, DotNetObjectReference.Create<object>(this));
        }
    }

    private bool _hasMoreChanged;

    protected override void OnParametersSet() => _hasMoreChanged = true;

    protected override async Task OnAfterRenderAsync_ReObserve()
    {
        // Handled via OnAfterRenderAsync below
    }

